#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        long long **dp = (long long **)malloc(N * sizeof(long long *));
        for (int i = 0; i < N; i++) {
            dp[i] = (long long *)malloc(M * sizeof(long long));
        }
        for (int j = 0; j < M; j++) {
            if ((1 + j) % 2 == 0) {
                dp[0][j] = 1;
            } else {
                dp[0][j] = 0;
            }
        }
        for (int i = 1; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (i % 2 == 1) {
                    if ((i + j) % 2 == 0) {
                        if (j > 0) {
                            dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % MOD;
                        }
                        dp[i][j] = (dp[i][j] + dp[i - 1][j]) % MOD;
                        if (j < M - 1) {
                            dp[i][j] = (dp[i][j] + dp[i - 1][j + 1]) % MOD;
                        }
                    }
                } else {
                    if (j > 0) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % MOD;
                    }
                    dp[i][j] = (dp[i][j] + dp[i - 1][j]) % MOD;
                    if (j < M - 1) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][j + 1]) % MOD;
                    }
                }
            }
        }
        long long ans = 0;
        for (int j = 0; j < M; j++) {
            ans = (ans + dp[N - 1][j]) % MOD;
        }
        printf("%lld\n", ans);
        for (int i = 0; i < N; i++) {
            free(dp[i]);
        }
        free(dp);
    }
    return 0;
}

